# Eval harness for edge case instruction coverage
# Run with: pytest test_edge_cases.py -v
import pytest, json
from unittest.mock import patch, MagicMock
from edge_case_handler import EdgeCaseHandler, DEFAULT_RULES

handler = EdgeCaseHandler()
SYSTEM_SECTION = handler.build_system_prompt_section()

# --- fixtures for simulated LLM responses ---

FIXTURES = {
    "missing_field": {
        "input": "What is the customer's phone number?",
        "context": "",  # empty context — field is missing
        "expected_type": "missing_data",
    },
    "ambiguous_date": {
        "input": "When was the contract signed on 01/02/03?",
        "context": "Contract details are in section 4.",
        "expected_type": "ambiguous_input",
    },
    "conflicting_revenue": {
        "input": "What was Q3 revenue?",
        "context": "Exec summary: Q3 revenue was $4.2M. CFO notes: Q3 revenue was $3.9M.",
        "expected_type": "conflicting_sources",
    },
    "ood_request": {
        "input": "Write a poem about the company.",
        "context": "Annual report 2024.",
        "expected_type": "out_of_distribution",
    },
}

def make_simulated_response(ec_type: str, detail: str = "test") -> dict:
    return {"status": "edge_case", "type": ec_type, "detail": detail}

@pytest.mark.parametrize("fixture_name,fixture", FIXTURES.items())
def test_edge_case_type_is_valid(fixture_name, fixture):
    """Simulated agent response must be a recognized edge case type."""
    simulated = make_simulated_response(fixture["expected_type"])
    is_valid, reason = handler.validate_response(simulated)
    assert is_valid, f"Fixture {fixture_name}: {reason}"
    assert simulated["type"] == fixture["expected_type"]

def test_system_prompt_section_contains_all_types():
    """The generated prompt section must mention every rule type."""
    for rule in DEFAULT_RULES:
        assert rule.ec_type.replace("_", " ").title().lower() in SYSTEM_SECTION.lower(), \
            f"Missing rule type in prompt section: {rule.ec_type}"

def test_nominal_response_passes_validation():
    resp = {"result": {"answer": "The revenue was $4.2M."}}
    is_valid, reason = handler.validate_response(resp)
    assert is_valid
    assert reason == "nominal"

def test_malformed_edge_case_fails_validation():
    resp = {"status": "edge_case"}  # missing 'type' field
    is_valid, reason = handler.validate_response(resp)
    assert not is_valid
    assert "missing fields" in reason
